// ===== Filter & Parse incoming JSON by id =====

// 1. Clean the raw string
let raw = msg.payload.toString().trim();

// 2. Extract valid JSON boundaries
let start = raw.indexOf('{');
let end = raw.lastIndexOf('}');

if (start === -1 || end === -1 || end <= start) {
    node.warn("Dropped: malformed JSON string → " + raw.substring(0, 120));
    return null;
}

raw = raw.substring(start, end + 1);

// 2.5 Fix: replace bare nan/NaN/Nan with null (invalid JSON from firmware)
raw = raw.replace(/:\s*nan\b/gi, ': null');

// 3. Parse JSON safely
let parsed;
try {
    parsed = JSON.parse(raw);
} catch (e) {
    node.warn("Dropped: JSON parse error → " + e.message + " | raw: " + raw.substring(0, 120));
    return null;
}

// 4. Filter by id
if (!parsed.id || parsed.id.trim().toLowerCase() !== "abdelghani") {
    return null;
}

// 5. Validate only required fields (BMP180 fields are optional)
const requiredFields = ["wind_speed", "wind_dir", "temperature", "humidity", "irradiance"];
const missingFields = requiredFields.filter(f => parsed[f] === undefined || parsed[f] === null);

if (missingFields.length > 0) {
    node.warn("Dropped: missing/null fields → " + missingFields.join(", "));
    return null;
}

// 5.5 Detect BMP180 presence
const bmp180Present = parsed.pressure !== null && parsed.pressure !== undefined
                   && parsed.altitude !== null && parsed.altitude !== undefined;

if (!bmp180Present) {
    node.warn("BMP180 absent: pressure & altitude set to null");
}

// 6. Build clean validated payload
msg.payload = {
    id: parsed.id.trim(),
    wind_speed:  parseFloat(parsed.wind_speed),
    wind_dir:    parseFloat(parsed.wind_dir),
    temperature: parseFloat(parsed.temperature),
    humidity:    parseFloat(parsed.humidity),
    irradiance:  parseFloat(parsed.irradiance),
    pressure:    bmp180Present ? parseFloat(parsed.pressure) : null,
    altitude:    bmp180Present ? parseFloat(parsed.altitude) : null,
    received_at: new Date().toISOString()
};

// 7. Sanity range checks (only for non-null values)
const ranges = {
    temperature: [-40, 80],
    humidity:    [0, 100],
    altitude:    [-500, 9000],
    pressure:    [0, 120],
    irradiance:  [0, 2000],
    wind_speed:  [0, 60],
    wind_dir:    [0, 359]
};

for (let [field, [min, max]] of Object.entries(ranges)) {
    let val = msg.payload[field];
    if (val === null) continue; // skip optional missing fields
    if (isNaN(val) || val < min || val > max) {
        node.warn(`Dropped: ${field} out of range → ${val} (expected ${min}–${max})`);
        return null;
    }
}

// 8. Visual status on node
const bmpStatus = bmp180Present
    ? `${msg.payload.pressure}hPa`
    : `no BMP180`;

node.status({ fill: "green", shape: "dot", text: `✓ ${msg.payload.temperature}°C | ${msg.payload.humidity}% | ${bmpStatus}` });

return msg;

msg.payload = {
    id: msg.payload.id,
    temperature: msg.payload.temperature,
    humidity: msg.payload.humidity,
    pressure: msg.payload.pressure,
    altitude: msg.payload.altitude,
    irradiance: msg.payload.irradiance,
    wind_speed: msg.payload.wind_speed,
    wind_dir: msg.payload.wind_dir,
    timestamp: new Date().toISOString()
};
msg.headers = { "Content-Type": "application/json" };
return msg;

// ===== Filter & Validate incoming weather data =====

// Le nœud JSON a déjà converti msg.payload en objet JS
if (typeof msg.payload !== "object" || msg.payload === null) {
    node.warn("Dropped: payload is not a valid object");
    return null;
}

let parsed = msg.payload;

// 1. Filter by id
if (!parsed.id || parsed.id.toString().trim().toLowerCase() !== "abdelghani") {
    return null;
}

// 2. Validate required fields
const requiredFields = [
    "wind_speed",
    "wind_dir",
    "temperature",
    "humidity",
    "irradiance"
];

const missingFields = requiredFields.filter(
    f => parsed[f] === undefined || parsed[f] === null
);

if (missingFields.length > 0) {
    node.warn("Dropped: missing/null fields → " + missingFields.join(", "));
    return null;
}

// 3. Detect BMP180 presence
const bmp180Present =
    parsed.pressure !== undefined &&
    parsed.pressure !== null &&
    parsed.altitude !== undefined &&
    parsed.altitude !== null;

if (!bmp180Present) {
    node.warn("BMP180 absent: pressure & altitude set to null");
}

// 4. Build clean payload
msg.payload = {
    id: parsed.id.toString().trim(),
    wind_speed: parseFloat(parsed.wind_speed),
    wind_dir: parseFloat(parsed.wind_dir),
    temperature: parseFloat(parsed.temperature),
    humidity: parseFloat(parsed.humidity),
    irradiance: parseFloat(parsed.irradiance),
    pressure: bmp180Present ? parseFloat(parsed.pressure) : null,
    altitude: bmp180Present ? parseFloat(parsed.altitude) : null,
    received_at: new Date().toISOString()
};

// 5. Sanity checks
const ranges = {
    temperature: [-40, 80],
    humidity: [0, 100],
    altitude: [-500, 9000],
    pressure: [0, 120],
    irradiance: [0, 2000],
    wind_speed: [0, 60],
    wind_dir: [0, 359]
};

for (const [field, [min, max]] of Object.entries(ranges)) {

    const val = msg.payload[field];

    if (val === null) continue;

    if (isNaN(val) || val < min || val > max) {
        node.warn(
            `Dropped: ${field} out of range → ${val} (expected ${min}-${max})`
        );
        return null;
    }
}

// 6. Node status
const bmpStatus = bmp180Present
    ? `${msg.payload.pressure} hPa`
    : "no BMP180";

node.status({
    fill: "green",
    shape: "dot",
    text: `✓ ${msg.payload.temperature}°C | ${msg.payload.humidity}% | ${bmpStatus}`
});

return msg;

if (typeof msg.payload === 'object') {
    if (msg.payload.id !== 'abdellah') {
        node.status({ fill:'grey', shape:'ring', text:'Wrong id' });
        return null;
    }
    node.status({ fill:'green', shape:'dot', text:'abdellah OK' });
    return msg;
}

let line = '';
if (Buffer.isBuffer(msg.payload)) {
    line = msg.payload.toString('utf8').trim();
} else {
    line = String(msg.payload).trim();
}

if (!line) return null;

// Guard: catch the literal string '[object Object]' which means something
// upstream called String(obj) instead of JSON.stringify(obj)/serializeJson().
if (line === '[object Object]') {
    node.status({ fill:'red', shape:'ring', text:'Got [object Object] - upstream bug' });
    node.warn('Gateway: received literal "[object Object]" string - sender must use JSON.stringify()/serializeJson(), not String(obj).');
    return null;
}

const start = line.indexOf('{');
const end   = line.lastIndexOf('}');
if (start === -1 || end === -1) {
    node.status({ fill:'grey', shape:'ring', text:'Not JSON' });
    return null;
}
line = line.substring(start, end + 1);

let data;
try {
    data = JSON.parse(line);
} catch(err) {
    node.status({ fill:'red', shape:'ring', text:'Parse error' });
    return null;
}

if (data.id !== 'abdellah') {
    node.status({ fill:'grey', shape:'ring', text:'Wrong id' });
    return null;
}

msg.payload = data;
node.status({ fill:'green', shape:'dot', text:'abdellah OK' });
return msg;

// Normalizes/renames raw ESP32 fields into a clean, consistent JSON object
// and adds a gateway-side timestamp + gateway id for traceability.
// NOTE: percentage/ratio math here is unit normalization (mL/mV -> %, mS/cm),
// not irrigation decision logic - no thresholds or pump actions are decided here.

const d = msg.payload;

const pct_drainage = parseFloat(d.input_mL) > 0
    ? parseFloat(((parseFloat(d.drainage_mL || 0) / parseFloat(d.input_mL)) * 100).toFixed(1))
    : 0;

const ec_mscm = parseFloat((parseFloat(d.ec_drainage || 0) / 1000).toFixed(2));
const ph      = parseFloat(parseFloat(d.ph || 0).toFixed(2));

msg.payload = {
    id:            d.id || 'abdellah',
    weight_g:      parseFloat(d.weight_g)      || 0,
    pct_drainage:  pct_drainage,
    ec_mscm:       ec_mscm,
    ph:            ph,
    input_mL:      parseFloat(d.input_mL)      || 0,
    drainage_mL:   parseFloat(d.drainage_mL)   || 0,
    water_used_mL: parseFloat(d.water_used_mL) || 0,
    temp:          parseFloat(d.temp_drainage)  || 0,
    soil_pct:      parseFloat(d.soil_pct)       || 0,
    pump:          d.pump       || 'OFF',
    drain_pump:    d.drain_pump || 'OFF',
    timestamp:     d.timestamp || new Date().toISOString(),
    gateway:       'raspberry01'
};

msg.topic = 'irrigation/abdellah/data';

node.status({ fill:'blue', shape:'dot',
    text: `drain:${pct_drainage}% EC:${ec_mscm} pH:${ph} w:${d.weight_g}g` });

return msg;

// Basic structural validation only - NO interpretation of command meaning.
// Ensures payload is valid JSON and contains an 'id' field, then
// serializes it into the line format expected by the ESP32 over LoRa.

let cmd;

if (typeof msg.payload === 'string') {
    try {
        cmd = JSON.parse(msg.payload);
    } catch (err) {
        node.status({ fill:'red', shape:'ring', text:'Invalid JSON from MQTT' });
        node.warn('Gateway: received invalid JSON command on ' + msg.topic + ': ' + msg.payload);
        return null;
    }
} else if (typeof msg.payload === 'object' && msg.payload !== null) {
    cmd = msg.payload;
} else {
    node.status({ fill:'red', shape:'ring', text:'Unsupported payload type' });
    return null;
}

if (!cmd.id) {
    node.status({ fill:'red', shape:'ring', text:'Missing id field' });
    node.warn('Gateway: command missing "id" field, dropping: ' + JSON.stringify(cmd));
    return null;
}

// Serialize to single-line JSON for LoRa transmission
msg.payload = JSON.stringify(cmd) + '\n';

node.status({ fill:'green', shape:'dot', text:'CMD -> LoRa: ' + cmd.id });
return msg;
